DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGchoicemacros.pl", "contextForm.pl", "contextFraction.pl", "parserPopUp.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction"); Context()->noreduce('(-x)+y', '(-x)-y'); ($b, $h, $k) = (-9..-1,1..9)[NchooseK(18,3)]; $m = Fraction(($k-$b)/$h); $f[0] = Formula("$m x + $b")->reduce; $f[1] = Formula("$m(x - $h) + $k")->reduce; $dropdown = DropDown(["Zero", "One", "Two", "More than two but finitely many", "Infinitely many"], 4, showInStatic => 0); $dropdown2 = DropDown(["Dependent", "Inconsistent", "None of the above"], 0, showInStatic => 0);
############################################################ # Body ############################################################
BEGIN_PGML Simply by looking closely at the linear equations, determine how many solutions the system will have. And state whether the system is dependent, inconsistent, or neither.
[`\newcommand{\amp}{&} \left\{ \begin{alignedat}{3} y \amp= [$f[0]]\\ y \amp= [$f[1]] \end{alignedat} \right. `]
[_]{$dropdown}{5}
[_]{$dropdown2}{5}
END_PGML
############################################################ # End Problem ############################################################
